def monitor_token_burn_rate(agent: Agent, max_tokens_per_call=5000):
    token_usage = []
    for response in agent.responses:
        tokens = response.usage.total_tokens
        token_usage.append(tokens)
        avg_usage = sum(token_usage) / len(token_usage)
        if avg_usage > max_tokens_per_call * 1.2:
            print(f'⚠️  Budget alert: {avg_usage:.0f} tokens/call (limit: {max_tokens_per_call})')
            return {'alert': 'HIGH_BURN_RATE', 'avg_tokens': avg_usage}
    return None

def scan_tracing_overhead(trace):
    trace_tokens = 0
    agent_tokens = 0
    for event in trace.events:
        if event.type.startswith('trace'):
            trace_tokens += event.metadata.get('tokens', 0)
        elif event.type == 'agent_response':
            agent_tokens += event.metadata.get('tokens', 0)

    if trace_tokens > agent_tokens * 0.3:
        return {
            'issue': 'EXCESSIVE_TRACING',
            'trace_ratio': trace_tokens / (trace_tokens + agent_tokens),
            'savings_potential': trace_tokens * 0.7
        }
    return None

