from openai_agents import Agent

def budget_guardrail(agent: Agent, remaining_budget=10000):
    def check_cost_before_call(prompt: str):
        estimated_tokens = len(prompt.split()) * 1.3  # Conservative estimate
        if estimated_tokens > remaining_budget * 0.8:
            return {'error': 'BUDGET_EXCEEDED', 'estimated': estimated_tokens}
        return agent.run(prompt)
    return check_cost_before_call

# Apply to agents
safe_call = budget_guardrail(research_agent, remaining_budget=5000)

import re
from openai_agents import Tool

def validate_tool_output(tool: Tool, output: str):
    # Check for common failure patterns
    error_patterns = [
        r'error|exception|failed|invalid',
        r'null|undefined|none',
        r'\{\}\s*$',
    ]

    for pattern in error_patterns:
        if re.search(pattern, output, re.IGNORECASE):
            return False
    return True

# Wrap tool calls
@Tool
async def safe_web_search(query):
    result = await web_search(query)
    if not validate_tool_output(web_search, result):
        return {'validated': False, 'fallback': 'Tool failed validation'}
    return result
